public class ShareReceiverActivity extends AppCompatActivity {

    private TextView infoView;
    private TextView textView;
    private LinearLayout imagesContainer;

    private ActivityResultLauncher<Uri> persistablePermissionRequest;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        persistablePermissionRequest =
                registerForActivityResult(new ActivityResultContracts.TakePersistableUriPermission(),
                        new ActivityResultCallback<Uri>() {
                            @Override
                            public void onActivityResult(Uri result) {
                                // no-op
                            }
                        });

        setTitle("Shared Content");

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(dp(16), dp(16), dp(16), dp(16));
        root.setLayoutParams(new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.MATCH_PARENT
        ));

        infoView = new TextView(this);
        infoView.setTextSize(14f);
        infoView.setGravity(Gravity.START);
        infoView.setText("");
        root.addView(infoView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        textView = new TextView(this);
        textView.setTextSize(16f);
        textView.setMovementMethod(new ScrollingMovementMethod());
        textView.setTextIsSelectable(true);
        textView.setText("");
        textView.setVisibility(View.GONE);
        root.addView(textView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        TextView imagesHeader = new TextView(this);
        imagesHeader.setTextSize(16f);
        imagesHeader.setText("Images:");
        imagesHeader.setVisibility(View.GONE);
        root.addView(imagesHeader, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        ScrollView scroll = new ScrollView(this);
        scroll.setFillViewport(true);

        imagesContainer = new LinearLayout(this);
        imagesContainer.setOrientation(LinearLayout.VERTICAL);
        imagesContainer.setLayoutParams(new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));
        scroll.addView(imagesContainer);

        LinearLayout.LayoutParams scrollLp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                0
        );
        scrollLp.weight = 1f;
        root.addView(scroll, scrollLp);

        setContentView(root);

        handleIntent(getIntent(), imagesHeader);
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        clearUi();
        TextView imagesHeader = (TextView) ((LinearLayout) findViewById(android.R.id.content).getRootView()).getChildAt(2);
        handleIntent(intent, imagesHeader);
    }

    private void clearUi() {
        infoView.setText("");
        textView.setText("");
        textView.setVisibility(View.GONE);
        imagesContainer.removeAllViews();
    }

    private void handleIntent(Intent intent, TextView imagesHeader) {
        if (intent == null) {
            infoView.setText("No intent received.");
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        StringBuilder info = new StringBuilder();
        info.append("Action: ").append(action).append("\n");
        info.append("Type: ").append(type).append("\n");

        String sharedText = extractSharedText(intent);
        List<Uri> imageUris = extractSharedUris(intent);

        if (sharedText != null && !sharedText.trim().isEmpty()) {
            textView.setText(sharedText);
            textView.setVisibility(View.VISIBLE);
        }

        if (!imageUris.isEmpty()) {
            imagesHeader.setVisibility(View.VISIBLE);
            for (Uri uri : imageUris) {
                tryPersistableReadPermission(intent, uri);
                addImageView(uri);
                addUriText(uri);
            }
        } else {
            imagesHeader.setVisibility(View.GONE);
        }

        if ((sharedText == null || sharedText.trim().isEmpty()) && imageUris.isEmpty()) {
            info.append("No supported shared content found.\n");
            info.append("Extras: ").append(intent.getExtras());
        }

        infoView.setText(info.toString());
    }

    @Nullable
    private String extractSharedText(Intent intent) {
        String text = intent.getStringExtra(Intent.EXTRA_TEXT);
        if (text == null) text = intent.getStringExtra(Intent.EXTRA_PROCESS_TEXT);
        if (text == null) text = intent.getStringExtra(Intent.EXTRA_SUBJECT);

        CharSequence cs = intent.getCharSequenceExtra(Intent.EXTRA_TEXT);
        if (text == null && cs != null) text = cs.toString();

        return text;
    }

    private List<Uri> extractSharedUris(Intent intent) {
        List<Uri> uris = new ArrayList<>();

        if (Intent.ACTION_SEND.equals(intent.getAction())) {
            Uri u = intent.getParcelableExtra(Intent.EXTRA_STREAM);
            if (u != null) uris.add(u);

            Uri data = intent.getData();
            if (data != null && !uris.contains(data)) uris.add(data);
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(intent.getAction())) {
            ArrayList<Uri> list = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
            if (list != null) uris.addAll(list);
        } else if (Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri data = intent.getData();
            if (data != null) uris.add(data);
        }

        String type = intent.getType();
        if (type != null && type.startsWith("text/")) {
            return new ArrayList<>();
        }

        List<Uri> filtered = new ArrayList<>();
        for (Uri uri : uris) {
            if (uri == null) continue;
            String scheme = uri.getScheme();
            if ("content".equalsIgnoreCase(scheme) || "file".equalsIgnoreCase(scheme) || "android.resource".equalsIgnoreCase(scheme)) {
                filtered.add(uri);
            }
        }
        return filtered;
    }

    private void tryPersistableReadPermission(Intent intent, Uri uri) {
        if (uri == null) return;

        int flags = intent.getFlags();
        boolean hasGrantRead = (flags & Intent.FLAG_GRANT_READ_URI_PERMISSION) != 0;
        boolean hasPersistable = (flags & Intent.FLAG_GRANT_PERSISTABLE_URI_PERMISSION) != 0;

        if (hasGrantRead && hasPersistable) {
            try {
                getContentResolver().takePersistableUriPermission(uri, Intent.FLAG_GRANT_READ_URI_PERMISSION);
            } catch (SecurityException ignored) {
            }
        }
    }

    private void addImageView(Uri uri) {
        ImageView iv = new ImageView(this);
        iv.setAdjustViewBounds(true);
        iv.setScaleType(ImageView.ScaleType.FIT_CENTER);
        iv.setImageURI(uri);

        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        );
        lp.topMargin = dp(12);
        imagesContainer.addView(iv, lp);
    }

    private void addUriText(Uri uri) {
        TextView tv = new TextView(this);
        tv.setTextSize(12f);
        tv.setTextIsSelectable(true);
        tv.setText(String.valueOf(uri));
        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        );
        lp.topMargin = dp(4);
        imagesContainer.addView(tv, lp);
    }

    private int dp(int v) {
        float d = getResources().getDisplayMetrics().density;
        return Math.round(v * d);
    }
}

